157	// resolveExecuteRoute reduces the request to a concrete RouteDecision.
158	// The request is dispatched through the routing engine
159	// (internal/routing.Resolve) when under-specified, or accepted verbatim
160	// when Harness is set explicitly.
161	func (s *service) resolveExecuteRoute(req ServiceExecuteRequest) (*RouteDecision, error) {
162		// If Harness is omitted, route through the engine. The engine defaults to
163		// local-first and auto-selects from configured endpoints when no other
164		// constraints are specified — an empty request is valid if providers exist.
165		if req.Harness == "" {
166			return s.resolveExecuteRouteWithEngine(req)
167		}
168		canonical := harnesses.ResolveHarnessAlias(req.Harness)
169		if !s.registry.Has(canonical) {
170			return nil, fmt.Errorf("unknown harness %q", req.Harness)
171		}
172		cfg, _ := s.registry.Get(canonical)
173		if err := validateExplicitHarnessProfile(canonical, cfg, req.Profile); err != nil {
174			return nil, err
175		}
176		if err := validateExplicitProvider(s.opts.ServiceConfig, cfg, req.Provider); err != nil {
177			return nil, err
178		}
179		if err := validateExplicitHarnessModel(canonical, cfg, req.Model, req.Provider); err != nil {
180			return nil, err
181		}
182		if err := validateExplicitHarnessReasoning(canonical, cfg, req.Reasoning); err != nil {
183			return nil, err
184		}
185		if err := validateExplicitHarnessQuota(canonical, cfg); err != nil {
186			return nil, err
187		}
188		resolvedModel := resolveSubprocessModelAlias(canonical, req.Model)
189		decision := &RouteDecision{
190			Harness:  canonical,
191			Provider: req.Provider,
192			Model:    resolvedModel,
193			Reason:   "explicit",
194			Power:    catalogPowerForModel(serviceRoutingCatalog(), resolvedModel),
195		}
196		if decision.Endpoint == "" {
197			_, endpoint, _ := splitEndpointProviderRef(decision.Provider)
198			decision.Endpoint = endpoint
199		}
200		return decision, nil
201	}
