203	func validateExplicitHarnessQuota(name string, cfg harnesses.HarnessConfig) error {
204		if !cfg.IsSubscription {
205			return nil
206		}
207		now := time.Now()
208		qs, ok := subscriptionQuotaForHarness(name, now)
209		if !ok || !qs.Present || !qs.Fresh || qs.OK {
210			return nil
211		}
212		return explicitQuotaUnavailable(name, qs.Windows, now)
213	}
214	
215	func explicitQuotaUnavailable(name string, windows []harnesses.QuotaWindow, now time.Time) error {
216		retryAfter := earliestQuotaResetAfter(windows, now)
217		if retryAfter.IsZero() {
218			retryAfter = now.Add(defaultQuotaRecoveryFallbackInterval)
219		}
220		return &NoViableProviderForNow{
221			RetryAfter:         retryAfter,
222			ExhaustedProviders: []string{name},
223		}
224	}
225	
226	func earliestQuotaResetAfter(windows []harnesses.QuotaWindow, now time.Time) time.Time {
227		var earliest time.Time
228		for _, window := range windows {
229			if window.ResetsAtUnix <= 0 {
230				continue
231			}
232			reset := time.Unix(window.ResetsAtUnix, 0)
233			if !reset.After(now) {
234				continue
235			}
236			if earliest.IsZero() || reset.Before(earliest) {
237				earliest = reset
238			}
239		}
240		return earliest
241	}
