243	func validateExplicitHarnessProfile(name string, cfg harnesses.HarnessConfig, profile string) error {
244		constraint, ok := explicitProfileConstraint(profile)
245		if !ok {
246			return nil
247		}
248		switch constraint {
249		case routing.ProviderPreferenceLocalOnly:
250			if !cfg.IsLocal {
251				return &ErrProfilePinConflict{
252					Profile:           profile,
253					ConflictingPin:    "Harness=" + name,
254					ProfileConstraint: constraint,
255				}
256			}
257		case routing.ProviderPreferenceSubscriptionOnly:
258			if !cfg.IsSubscription {
259				return &ErrProfilePinConflict{
260					Profile:           profile,
261					ConflictingPin:    "Harness=" + name,
262					ProfileConstraint: constraint,
263				}
264			}
265		}
266		return nil
267	}
268	
269	func explicitProfileConstraint(profile string) (string, bool) {
270		switch profile {
271		case "local", "offline", "air-gapped":
272			return routing.ProviderPreferenceLocalOnly, true
273		case "smart", "code-smart", "code-high":
274			return routing.ProviderPreferenceSubscriptionOnly, true
275		default:
276			return "", false
277		}
278	}
