280	func isExplicitPinError(err error) bool {
281		var modelConstraintAmbiguous *ErrModelConstraintAmbiguous
282		if errors.As(err, &modelConstraintAmbiguous) {
283			return true
284		}
285		var modelConstraintNoMatch *ErrModelConstraintNoMatch
286		if errors.As(err, &modelConstraintNoMatch) {
287			return true
288		}
289		var modelErr *ErrHarnessModelIncompatible
290		if errors.As(err, &modelErr) {
291			return true
292		}
293		var profileErr *ErrProfilePinConflict
294		if errors.As(err, &profileErr) {
295			return true
296		}
297		var providerErr *ErrUnknownProvider
298		return errors.As(err, &providerErr)
299	}
