301	// validateExplicitProvider rejects pre-dispatch when the caller pinned a
302	// provider name that the service configuration does not recognize. Returns
303	// nil when no provider was pinned, when no ServiceConfig is configured (no
304	// provider catalog to validate against), when the provider name is known,
305	// or when the harness is test-only / does not consume Provider (virtual,
306	// script, etc. have no real provider lookup).
307	func validateExplicitProvider(sc ServiceConfig, cfg harnesses.HarnessConfig, provider string) error {
308		if provider == "" || sc == nil {
309			return nil
310		}
311		if cfg.TestOnly {
312			return nil
313		}
314		lookup := provider
315		if base, _, ok := splitEndpointProviderRef(provider); ok {
316			lookup = base
317		}
318		if _, ok := sc.Provider(lookup); ok {
319			return nil
320		}
321		known := sc.ProviderNames()
322		return &ErrUnknownProvider{Provider: provider, KnownProviders: append([]string(nil), known...)}
323	}
