325	func validateExplicitHarnessModel(name string, cfg harnesses.HarnessConfig, model, provider string) error {
326		if model == "" || cfg.TestOnly || cfg.IsHTTPProvider || name == "fiz" {
327			return nil
328		}
329		if modelSupportedForHarness(name, cfg, model, provider) {
330			return nil
331		}
332		supportedModels := subprocessHarnessModelIDs(name, cfg)
333		return &ErrHarnessModelIncompatible{
334			Harness:         name,
335			Model:           model,
336			SupportedModels: append([]string(nil), supportedModels...),
337		}
338	}
339	
340	func modelSupportedForHarness(name string, cfg harnesses.HarnessConfig, model, provider string) bool {
341		for _, known := range subprocessHarnessModelIDs(name, cfg) {
342			if model == known {
343				return true
344			}
345		}
346		switch name {
347		case "codex":
348			return strings.HasPrefix(model, "gpt-")
349		case "claude":
350			return strings.HasPrefix(model, "claude-")
351		case "pi":
352			// Pi can route to non-Gemini backends (lmstudio, omlx, etc.) when a
353			// provider is pinned. The pi CLI owns per-provider model validation
354			// in that case, so the agent-side gate trusts the provider pin and
355			// defers concrete model-ID checks to pi --list-models / pi itself.
356			return provider != ""
357		default:
358			return len(cfg.Models) == 0
359		}
360	}
