362	func validateExplicitHarnessReasoning(name string, cfg harnesses.HarnessConfig, value Reasoning) error {
363		if cfg.TestOnly {
364			return nil
365		}
366		if len(cfg.ReasoningLevels) == 0 && cfg.MaxReasoningTokens <= 0 {
367			return nil
368		}
369		policy, err := reasoning.ParseString(string(value))
370		if err != nil {
371			return fmt.Errorf("unsupported reasoning %q for harness %q: %w", value, name, err)
372		}
373		switch policy.Kind {
374		case reasoning.KindUnset, reasoning.KindAuto, reasoning.KindOff:
375			return nil
376		case reasoning.KindTokens:
377			if cfg.MaxReasoningTokens <= 0 {
378				return fmt.Errorf("unsupported reasoning %q for harness %q; token budgets are not supported", value, name)
379			}
380			if policy.Tokens > cfg.MaxReasoningTokens {
381				return fmt.Errorf("unsupported reasoning %q for harness %q; max token budget is %d", value, name, cfg.MaxReasoningTokens)
382			}
383			return nil
384		case reasoning.KindNamed:
385			for _, supported := range cfg.ReasoningLevels {
386				if string(policy.Value) == supported {
387					return nil
388				}
389			}
390			return fmt.Errorf("unsupported reasoning %q for harness %q; supported reasoning: %s", value, name, strings.Join(cfg.ReasoningLevels, ", "))
391		default:
392			return fmt.Errorf("unsupported reasoning %q for harness %q", value, name)
393		}
394	}
