403	// runExecute is the per-Execute goroutine. It owns the channel close path
404	// and the final event emit. All termination paths funnel through emitFinal
405	// so the channel always sees a final event before close.
406	func (s *service) runExecute(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, sessionID string, overrideCtx *overrideContext) {
407		defer close(out)
408	
409		start := time.Now()
410		var seq atomic.Int64
411	
412		// Open the service-owned session log writer and guarantee a terminal
413		// session.end record plus a clean file close even on unexpected exits.
414		// CONTRACT-003 makes session-log lifecycle a service responsibility; the
415		// per-path finalizeAndEmit calls below feed writeEnd in lock-step with
416		// the public final event.
417		sl := s.executeSessionLogOpener().openSessionLog(req, decision, sessionID)
418		if overrideCtx != nil {
419			sl.override = overrideCtx
420		}
421		defer func() {
422			if !sl.endWritten() {
423				sl.writeEnd(req, meta, harnesses.FinalData{
424					Status:     "cancelled",
425					Error:      "session ended without final event",
426					DurationMS: time.Since(start).Milliseconds(),
427					RoutingActual: &harnesses.RoutingActual{
428						Harness:  decision.Harness,
429						Provider: decision.Provider,
430						Model:    decision.Model,
431					},
432				})
433			}
434			sl.close()
435		}()
436	
437		// Wall-clock cap.
438		runCtx := ctx
439		if req.Timeout > 0 {
440			var cancel context.CancelFunc
441			runCtx, cancel = context.WithTimeout(ctx, req.Timeout)
442			defer cancel()
443		}
444	
445		// Emit routing_decision start event. Include session_id so callers can
446		// extract it and pass to TailSessionLog. Per CONTRACT-003 the
447		// top-level Role + CorrelationID are echoed into routing_decision
448		// event Metadata (top-level wins over caller Metadata for these
449		// reserved keys).
450		routingMeta := metaWithRoleAndCorrelation(meta, req.Role, req.CorrelationID)
451		emitJSON(out, &seq, harnesses.EventTypeRoutingDecision, routingMeta, ServiceRoutingDecisionData{
452			Harness:        decision.Harness,
453			Provider:       decision.Provider,
454			Endpoint:       decision.Endpoint,
455			ServerInstance: decision.ServerInstance,
456			Model:          decision.Model,
457			Reason:         decision.Reason,
458			Sticky: ServiceRoutingStickyState{
459				KeyPresent:     decision.Sticky.KeyPresent,
460				Assignment:     decision.Sticky.Assignment,
461				ServerInstance: decision.Sticky.ServerInstance,
462				Reason:         decision.Sticky.Reason,
463				Bonus:          decision.Sticky.Bonus,
464			},
465			Utilization: ServiceRoutingUtilizationState{
466				Source:         decision.Utilization.Source,
467				Freshness:      decision.Utilization.Freshness,
468				ActiveRequests: decision.Utilization.ActiveRequests,
469				QueuedRequests: decision.Utilization.QueuedRequests,
470				MaxConcurrency: decision.Utilization.MaxConcurrency,
471				CachePressure:  decision.Utilization.CachePressure,
472				ObservedAt:     decision.Utilization.ObservedAt,
473			},
474			RequestedHarness: req.Harness,
475			HarnessSource:    harnessSource(req),
476			SessionID:        sessionID,
477			Candidates:       routingDecisionEventCandidates(decision.Candidates),
478		})
479		emitProgress(out, &seq, sl, sessionID, meta, routeProgressData(decision))
480	
481		s.executeRunnerInvoker().dispatchExecuteRun(runCtx, executeRunContext{
482			req:      req,
483			decision: decision,
484			meta:     meta,
485			out:      out,
486			seq:      &seq,
487			start:    start,
488			sl:       sl,
489			session:  sessionID,
490		})
491	}
