493	func (s *service) runVirtual(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string) {
494		progress := newSubprocessProgressState(req)
495		emitProgress(out, seq, sl, sessionID, meta, progress.noteRequestStart())
496		result := serviceimpl.RunVirtual(ctx, executeRunnerRequest(req, decision, meta, start))
497		final := result.Final
498		if result.EmitText {
499			emitJSONRaw(out, seq, harnesses.EventTypeTextDelta, meta, harnesses.TextDeltaData{Text: result.Text})
500		}
501		if progressFinal := progress.noteResponseComplete(final); progressFinal != nil {
502			emitProgress(out, seq, sl, sessionID, meta, *progressFinal)
503		}
504		finalizeAndEmit(out, seq, meta, req, sl, final)
505	}
