542	// runNative drives the in-process agent loop (loop.go's Run). The provider
543	// is wrapped so per-HTTP timeouts fire independently of the request wall-clock
544	// cap.
545	func (s *service) runNative(ctx context.Context, req ServiceExecuteRequest, decision RouteDecision, meta map[string]string, out chan<- ServiceEvent, seq *atomic.Int64, start time.Time, sl *serviceSessionLog, sessionID string) {
546		progress := newNativeProgressState()
547		observeAgentEvent := func(ev agentcore.Event) {
548			sl.writeEvent(ev)
549			switch ev.Type {
550			case agentcore.EventLLMRequest:
551				var payload nativeLLMRequestPayload
552				if err := json.Unmarshal(ev.Data, &payload); err == nil {
553					emitProgress(out, seq, sl, sessionID, meta, progress.noteRequest(payload))
554				}
555			case agentcore.EventLLMResponse:
556				var payload nativeLLMResponsePayload
557				if err := json.Unmarshal(ev.Data, &payload); err == nil {
558					emitProgress(out, seq, sl, sessionID, meta, progress.noteResponse(payload))
559				}
560			case agentcore.EventToolCall:
561				var payload nativeToolCallPayload
562				_ = json.Unmarshal(ev.Data, &payload)
563				toolName := payload.Tool
564				input := payload.Input
565				if input == nil {
566					if rawIn, err := json.Marshal(map[string]any{"tool": toolName}); err == nil {
567						input = rawIn
568					}
569				}
570				callID := fmt.Sprintf("call-%d", ev.Seq)
571				_, completeProgress := progress.noteToolCall(callID, payload)
572				emitJSONRaw(out, seq, harnesses.EventTypeToolCall, meta, harnesses.ToolCallData{
573					ID:    callID,
574					Name:  toolName,
575					Input: input,
576				})
577				emitJSONRaw(out, seq, harnesses.EventTypeToolResult, meta, harnesses.ToolResultData{
578					ID:         callID,
579					Output:     payload.Output,
