711	func newServiceCompactor(req ServiceExecuteRequest, model string) agentcore.Compactor {
712		cfg := compaction.DefaultConfig()
713		if req.CompactionContextWindow > 0 {
714			cfg.ContextWindow = req.CompactionContextWindow
715			if cfg.ReserveTokens >= cfg.ContextWindow {
716				cfg.ReserveTokens = 0
717			}
718			if cfg.KeepRecentTokens > cfg.ContextWindow {
719				cfg.KeepRecentTokens = cfg.ContextWindow / 2
720			}
721		}
722		if req.CompactionReserveTokens > 0 {
723			cfg.ReserveTokens = req.CompactionReserveTokens
724		}
725		if catalog, err := modelcatalog.Default(); err == nil && catalog != nil && model != "" && req.CompactionContextWindow <= 0 {
726			if contextWindow := catalog.ContextWindowForModel(model); contextWindow > 0 {
727				cfg.ContextWindow = contextWindow
728			}
729		}
730		return compaction.NewCompactor(cfg)
