800	// emitFinal wraps a FinalData into a ServiceEvent and writes it to out.
801	// The channel close happens in the caller via defer; this only writes the
802	// terminator event.
803	func emitFinal(out chan<- ServiceEvent, seq *atomic.Int64, meta map[string]string, final harnesses.FinalData) {
804		raw, err := json.Marshal(final)
805		if err != nil {
806			raw = []byte(`{"status":"failed","error":"marshal final"}`)
807		}
808		ev := harnesses.Event{
809			Type:     harnesses.EventTypeFinal,
810			Sequence: seq.Add(1) - 1,
811			Time:     time.Now().UTC(),
812			Metadata: meta,
813			Data:     raw,
814		}
815		select {
816		case out <- ev:
817		case <-time.After(time.Second):
818		}
819	}
