866	// finalizeAndEmit stamps the service-owned session-log path onto final,
867	// records the terminal session.end event, and forwards the final to the
868	// public event stream. Every terminal emit path in runExecute funnels
869	// through this helper so the session log and the event channel stay in
870	// lock-step (CONTRACT-003).
871	//
872	// finalizeAndEmit also performs the CONTRACT-003 echo of top-level Role
873	// and CorrelationID into the final event Metadata (top-level wins over
874	// any caller-supplied Metadata entry under the same reserved key) and
875	// stamps RoutingActual.Power from the catalog projection of the
876	// actually-dispatched Model. When the caller set both top-level
877	// Role/CorrelationID and the same reserved Metadata key, a
878	// MetadataKeyCollision warning is appended to final.Warnings.
879	func finalizeAndEmit(out chan<- ServiceEvent, seq *atomic.Int64, meta map[string]string, req ServiceExecuteRequest, sl *serviceSessionLog, final harnesses.FinalData) {
880		if sl != nil && sl.path != "" {
881			final.SessionLogPath = sl.path
882		}
883		// Stamp catalog power onto the actually-dispatched RoutingActual.
884		// final.RoutingActual is set by the caller (one per terminal path);
885		// when nil we leave it nil to avoid synthesizing routing evidence.
886		if final.RoutingActual != nil && final.RoutingActual.Power == 0 {
887			final.RoutingActual.Power = catalogPowerForModel(serviceRoutingCatalog(), final.RoutingActual.Model)
888		}
889		// Detect reserved metadata-key collisions and append a warning so the
890		// caller learns when their caller-supplied Metadata entries were
891		// overridden by the top-level Role / CorrelationID fields.
892		if collisions := metadataReservedKeyCollisions(req.Metadata, req.Role, req.CorrelationID); len(collisions) > 0 {
893			final.Warnings = append(final.Warnings, harnesses.FinalWarning{
894				Code:    MetadataWarningCodeKeyCollision,
895				Message: metadataKeyCollisionMessage(collisions),
896			})
897		}
898		// Echo Role + CorrelationID onto the final event Metadata.
899		finalMeta := metaWithRoleAndCorrelation(meta, req.Role, req.CorrelationID)
900		if sl != nil {
901			if ovr := sl.override; ovr != nil && !ovr.emitted.Load() {
902				sl.writeOverrideEvent(ServiceEventTypeOverride, ovr.payload)
903			}
904			sl.writeEnd(req, finalMeta, final)
905		}
906		emitFinal(out, seq, finalMeta, final)
907	}
